@fleer.paranoia += 4


// ── The plan: intrigue-plot ──────────────────────────────────────────────────
//
// Queued by mail-dossier. It runs a rumour, an interception of the dossier, and
// a final confrontation that precasts the original mail-dossier action into the
// @triggering role — a causal edge that does NOT pass through the normal
// reaction chain. In a sifting-match diagram this shows up as a convergence.

queue plan intrigue-plot:
            with:
                @sender: @sender
                @target: @target
                @parcel: @dossier
                @triggering: @this


// ── Notice lineage ───────────────────────────────────────────────────────────

queue action share-rumour:
            with:
                @speaker: @listener
                @confidant: @source
            time:
                between: 1 minutes and 3 minutes from action

queue action confront:
            with:
                @accuser: @listener
                @accused: @source
            abandon:
                @listener.paranoia < 55
            time:
                between: 0 minutes and 5 minutes from action

queue action read-notice:
            with:
                @reader: @poster
                @board: @board
            time:
                between: 0 minutes and 12 minutes from action

queue action overhear:
            with:
                @listener: @confidant
                @source: @speaker
            time:
                between: 0 minutes and 3 minutes from action

queue action read-letter:
            with:
                @reader: @receiver
                @letter: @note
            time:
                between: 5 minutes and 20 minutes from action
